import{_ as t,o as a,c as i,ae as n}from"./chunks/framework.B6gjLfeO.js";const g=JSON.parse('{"title":"Manage Billing (New)","description":"","frontmatter":{"title":"Manage Billing (New)","slug":"billing-manage-new"},"headers":[],"relativePath":"account-hub/billing-manage-new.md","filePath":"account-hub/billing-manage-new.md"}'),o={name:"account-hub/billing-manage-new.md"};function r(s,e,l,d,c,h){return a(),i("div",null,[...e[0]||(e[0]=[n('<h2 id="required-permissions" tabindex="-1">Required permissions <a class="header-anchor" href="#required-permissions" aria-label="Permalink to &quot;Required permissions&quot;">​</a></h2><p>In order to view/edit specific billing details, you need to have the correct access and permission level:</p><table tabindex="0"><thead><tr><th>Billing feature</th><th>Permission requirement</th></tr></thead><tbody><tr><td>- Your Plan - Usage Statistics - Subscribed Products</td><td><strong>View</strong> access to <strong>App-level Settings</strong></td></tr><tr><td>- Payment Info (credit cards) - View/download invoices - Billing contact info</td><td><strong>View</strong> access to <strong>App-level Settings</strong> and <strong>Sensitive Data</strong></td></tr><tr><td>- Change plans - View/download invoices - Cancel subscriptions</td><td><strong>Edit</strong> access to <strong>App-level Settings</strong></td></tr><tr><td>- Add/edit/delete credit card information</td><td><strong>Edit</strong> access to <strong>App-level Settings</strong> and <strong>Sensitive Data</strong></td></tr></tbody></table><p>For additional details on permissions, view our guide <a href="./add-manage-users-roles-permissions-access.html">here</a>.</p><h2 id="access-billing-features" tabindex="-1">Access billing features <a class="header-anchor" href="#access-billing-features" aria-label="Permalink to &quot;Access billing features&quot;">​</a></h2><p>Navigate to the <a href="https://branchdocs.app.link/billing-new-to-billing-settings" target="_blank" rel="noreferrer"><strong>Billing</strong></a> tab in <a href="https://branchdocs.app.link/e/home-page-to-dashboard" target="_blank" rel="noreferrer">Branch</a> to start using billing features.</p><p>The view you see in the <strong>Billing</strong> tab will depend on whether you have access to Branch’s new or legacy billing experience.</p><p>For more details on payment information, including how to add payment methods, view our <a href="./manage-billing.html">dedicated guide</a>.</p><h3 id="plan-details" tabindex="-1">Plan details <a class="header-anchor" href="#plan-details" aria-label="Permalink to &quot;Plan details&quot;">​</a></h3><p>The <strong>Billing</strong> tab is an overview of your Branch plan, including:</p><ul><li>The Branch <a href="./products.html">products, features, and add-ons</a> that are part of your plan</li><li>The number of volume credits you have purchased</li><li>Your billing cadence</li></ul><p>Use the <strong>Manage Plan</strong> button to make changes your Branch plan.</p><h3 id="volume-credit-usage" tabindex="-1">Volume credit usage <a class="header-anchor" href="#volume-credit-usage" aria-label="Permalink to &quot;Volume credit usage&quot;">​</a></h3><p>The <strong>Usage</strong> module displays the number of volume credits your app has used this month, out of the total number you’ve purchased. This resets monthly.</p><p>Use the <strong>Manage Plan</strong> button to make changes the number of volume credits available for your app.</p><h3 id="payment-information" tabindex="-1">Payment information <a class="header-anchor" href="#payment-information" aria-label="Permalink to &quot;Payment information&quot;">​</a></h3><p>The <strong>Payment information</strong> module is where you can see what payment method is being used for this Branch account.</p><p>You can use the <strong>Edit</strong> button to make changes to your payment information.</p><h3 id="estimated-upcoming-bill" tabindex="-1">Estimated upcoming bill <a class="header-anchor" href="#estimated-upcoming-bill" aria-label="Permalink to &quot;Estimated upcoming bill&quot;">​</a></h3><p>The <strong>Estimated upcoming bill</strong> module gives you an estimated projection of your upcoming invoice amount, and when it will be billed.</p><h3 id="invoice-history" tabindex="-1">Invoice history <a class="header-anchor" href="#invoice-history" aria-label="Permalink to &quot;Invoice history&quot;">​</a></h3><p>The <strong>Invoice history</strong> module gives you a high-level overview of your past invoices, including:</p><ul><li>Invoice number</li><li>Invoice date</li><li>Billing period</li><li>Invoice balance</li></ul><p>This module also lets you download individual invoices using the <strong>Invoice</strong> column.</p>',24)])])}const p=t(o,[["render",r]]);export{g as __pageData,p as default};
